        pygame.display.set_caption("TetrisBejeweled")
        self.clock = pygame.time.Clock()
        self.font = pygame.font.Font(None, 36)

        self.grid = Grid(GRID_WIDTH, GRID_HEIGHT)
        self.queue = NextQueue()
        self.score = 0
        self.chain = 1.0
        self.fall_interval = 500  # ms
        self.last_fall = pygame.time.get_ticks()
        self.game_over = False

        self.spawn()

    def spawn(self):
        kind = self.queue.pop()
        self.current = Tetromino(kind)
        if not self.grid.is_valid(kind, self.current.x, self.current.y, self.current.rot):
            self.game_over = True

    def move(self, dx, dy):
        nx, ny = self.current.x+dx, self.current.y+dy
        if self.grid.is_valid(self.current.kind, nx, ny, self.current.rot):
            self.current.x, self.current.y = nx, ny
            return True
        return False

    def rotate(self):
        old = self.current.rot
        self.current.rotate()
        if not self.grid.is_valid(self.current.kind, self.current.x, self.current.y, self.current.rot):
            self.current.rot = old

    def lock_and_clear(self):
