                if ev.key==pygame.K_UP:   self.rotate()
                if ev.key==pygame.K_DOWN:
                    if not self.move(0,1): self.lock_and_clear()
                if ev.key==pygame.K_SPACE:
                    while self.move(0,1): pass
                    self.lock_and_clear()
        return True

    def draw_block(self, x, y, color):
